true, &#34;outputKey&#34;: &#34;Vivid Pop Explosion&#34; } ] }, &#34;options&#34;: { &#34;fallbackOutput&#34;: &#34;extra&#34; } }, &#34;id&#34;: &#34;38a67bf8-8397-483f-acbc-7fa3b3def171&#34;, &#34;name&#34;: &#34;按风格路线&#34;, &#34;type&#34;: &#34;n8n-nodes-base.switch&#34;, &#34;position&#34;: [ -400, 340 ], &#34;typeVersion&#34;: 3.1, &#34;notesInFlow&#34;: true }, { &#34;parameters&#34;: { &#34;respondWith&#34;: &#34;text&#34;, &#34;responseBody&#34;: &#34;=&lt;!DOCTYPE html&gt;
&lt;html lang=\&#34;zh-CN\&#34;&gt;
&lt;head&gt;
 &lt;meta charset=\&#34;UTF-8\&#34;&gt;
 &lt;meta name=\&#34;viewport\&#34; content=\&#34;width=device-width, initial-scale=1.0\&#34;&gt;
 &lt;title&gt;Flux 图片生成结果&lt;/title&gt;
 &lt;style&gt;
 body {
 font-family: &#39;Open Sans&#39;, -apple-system, BlinkMacSystemFont, &#39;Segoe UI&#39;, Roboto, Arial, sans-serif;
 display: flex;
 flex-direction: column;
 align-items: center;
 justify-content: flex-start;
 min-height: 100vh;
 background-color: #121212;
 color: #e0e0e0;
 margin: 0;
 padding: 20px;
 }

 .container {
 width: 90%;
 max-width: 800px;
 text-align: center;
 background: linear-gradient(145deg, #1e1e1e, #242424);
 padding: 32px;
 border-radius: 16px;
 box-shadow: 0 8px 32px rgba(0, 0, 0, 0.4);
 margin-bottom: 32px;
 }

 .image-container {
 margin-bottom: 24px;
 }

 .image-container img {
 max-width: 100%;
 height: auto;
 border-radius: 12px;
 border: 2px solid #333;
 transition: transform 0.3s ease, box-shadow 0.3s ease;
 }

 .image-container img:hover {
 transform: scale(1.02);
 box-shadow: 0 12px 24px rgba(0, 0, 0, 0.5);
 }

 .style-text {
 font-size: 18px;
 margin: 24px 0;
 color: #bbb;
 padding: 12px;
 background: rgba(255, 255, 255, 0.05);
 border-radius: 8px;
 }

 .cta {
 display: inline-block;
 width: auto;
 min-width: 200px;
 margin: 20px 0 0;
 padding: 16px 32px;
 border: none;
 border-radius: 8px;
 text-decoration: none;
 color: #fff;
 background: linear-gradient(135deg, #1C9985, #20B69E);
 font-size: 18px;
 font-weight: 500;
 cursor: pointer;
 transition: all 0.3s ease;
 }

 .cta:hover {
 background: linear-gradient(135deg, #20B69E, #25D4B8);
 transform: translateY(-2px);
 box-shadow: 0 8px 16px rgba(28, 153, 133, 0.3);
 }

 .recent-renders {
 width: 90%;
 max-width: 800px;
 display: grid;
 grid-template-columns: repeat(2, 1fr);
 gap: 24px;
 margin-top: 32px;
 }

 .recent-render {
 background-color: #2c2c2c;
 padding: 16px;
 border-radius: 12px;
 transition: transform 0.3s ease, box-shadow 0.3s ease;
 }

 .recent-render:hover {
 transform: translateY(-4px);
 box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
 }

 .recent-render img {
 width: 100%;
 height: auto;
 border-radius: 8px;
 border: 2px solid #333;
 transition: transform 0.3s ease;
 }

 /* 隐藏额外的图片 */
 .recent-render:nth-child(n+5) {
 display: none;
 }

 /* 显示更多按钮样式 */
 .show-more-label {
 display: inline-block;
 width: 90%;
 max-width: 800px;
 margin: 32px auto;
 padding: 16px;
 background: #2c2c2c;
 color: #fff;
 border: none;
 border-radius: 8px;
 font-size: 16px;
 cursor: pointer;
 transition: all 0.3s ease;
 text-align: center;
 }

 .show-more-label:hover {
 background: #333;
 transform: translateY(-2px);
 }

 /* 隐藏复选框 */
 #show-more {
 display: none;
 }

 /* 当复选框被选中时显示额外的图片 */
 #show-more:checked ~ .recent-renders .recent-render:nth-child(n+5) {
 display: block;
 }

 /* 当复选框被选中时隐藏显示更多按钮 */
 #show-more:checked ~ .show-more-label {
 display: none;
 }

 @media (max-width: 768px) {
 .recent-renders {
 grid-template-columns: 1fr;
 }

 .container {
 padding: 20px;
 }
 }
 &lt;/style&gt;
&lt;/head&gt;
